import os
import time
import secrets
from typing import Dict, Optional

from flask import Flask, jsonify, request
from web3 import Web3
from eth_account.messages import encode_defunct

app = Flask(__name__)

w3 = Web3()

NONCE_TTL_SECONDS = int(os.getenv("NONCE_TTL_SECONDS", "300"))
SESSION_TTL_SECONDS = int(os.getenv("SESSION_TTL_SECONDS", "86400"))

nonces: Dict[str, Dict[str, int]] = {}
sessions: Dict[str, Dict[str, int]] = {}


def now_ts() -> int:
    return int(time.time())


def normalize_address(address: str) -> str:
    if not address:
        raise ValueError("address is required")
    if not w3.is_address(address):
        raise ValueError("invalid ethereum address")
    return w3.to_checksum_address(address)


def cleanup_expired() -> None:
    current = now_ts()

    expired_nonces = [
        addr for addr, data in nonces.items()
        if data["expires_at"] <= current
    ]
    for addr in expired_nonces:
        nonces.pop(addr, None)

    expired_sessions = [
        token for token, data in sessions.items()
        if data["expires_at"] <= current
    ]
    for token in expired_sessions:
        sessions.pop(token, None)


def create_nonce() -> str:
    return secrets.token_urlsafe(24)


def create_session_token() -> str:
    return secrets.token_urlsafe(32)


@app.before_request
def before_request_cleanup():
    cleanup_expired()


@app.get("/health")
def health():
    return jsonify({"status": "ok"}), 200


@app.post("/auth/nonce")
def auth_nonce():
    data = request.get_json(silent=True) or {}
    address = data.get("address")

    try:
        checksum_address = normalize_address(address)
    except ValueError as e:
        return jsonify({"error": str(e)}), 400

    nonce = create_nonce()
    issued_at = now_ts()
    expires_at = issued_at + NONCE_TTL_SECONDS

    nonces[checksum_address] = {
        "nonce": nonce,
        "issued_at": issued_at,
        "expires_at": expires_at,
    }

    message = f"Sign this message to authenticate.\n\nNonce: {nonce}\nAddress: {checksum_address}"

    return jsonify({
        "address": checksum_address,
        "nonce": nonce,
        "message": message,
        "issued_at": issued_at,
        "expires_at": expires_at,
    }), 200


@app.post("/auth/verify")
def auth_verify():
    data = request.get_json(silent=True) or {}
    address = data.get("address")
    signature = data.get("signature")
    message = data.get("message")

    if not signature or not isinstance(signature, str):
        return jsonify({"error": "signature is required"}), 400
    if not message or not isinstance(message, str):
        return jsonify({"error": "message is required"}), 400

    try:
        checksum_address = normalize_address(address)
    except ValueError as e:
        return jsonify({"error": str(e)}), 400

    nonce_record = nonces.get(checksum_address)
    if not nonce_record:
        return jsonify({"error": "no active nonce for address"}), 401

    expected_message = (
        f"Sign this message to authenticate.\n\n"
        f"Nonce: {nonce_record['nonce']}\n"
        f"Address: {checksum_address}"
    )

    if message != expected_message:
        return jsonify({"error": "message does not match expected authentication payload"}), 401

    try:
        encoded_message = encode_defunct(text=message)
        recovered_address = w3.eth.account.recover_message(encoded_message, signature=signature)
        recovered_address = w3.to_checksum_address(recovered_address)
    except Exception:
        return jsonify({"error": "invalid signature"}), 401

    if recovered_address != checksum_address:
        return jsonify({
            "error": "signature verification failed",
            "recovered_address": recovered_address,
        }), 401

    nonces.pop(checksum_address, None)

    token = create_session_token()
    issued_at = now_ts()
    expires_at = issued_at + SESSION_TTL_SECONDS

    sessions[token] = {
        "address": checksum_address,
        "issued_at": issued_at,
        "expires_at": expires_at,
    }

    return jsonify({
        "authenticated": True,
        "address": checksum_address,
        "session_token": token,
        "issued_at": issued_at,
        "expires_at": expires_at,
    }), 200


@app.get("/auth/me")
def auth_me():
    auth_header = request.headers.get("Authorization", "")
    if not auth_header.startswith("Bearer "):
        return jsonify({"error": "missing bearer token"}), 401

    token = auth_header.split(" ", 1)[1].strip()
    session = sessions.get(token)
    if not session:
        return jsonify({"error": "invalid or expired session"}), 401

    return jsonify({
        "authenticated": True,
        "address": session["address"],
        "issued_at": session["issued_at"],
        "expires_at": session["expires_at"],
    }), 200


@app.post("/auth/logout")
def auth_logout():
    auth_header = request.headers.get("Authorization", "")
    if not auth_header.startswith("Bearer "):
        return jsonify({"error": "missing bearer token"}), 401

    token = auth_header.split(" ", 1)[1].strip()
    if token in sessions:
        sessions.pop(token, None)
        return jsonify({"logged_out": True}), 200

    return jsonify({"error": "invalid or expired session"}), 401


